TASKS = {}
for track_id, track in TRACKS.items():
    TASKS[track_id] = track["tasks"]

def get_task(track_id, task_id):
    for t in TASKS.get(track_id, []):
        if t["id"] == task_id:
            return t
    return None

def get_all_tracks():
    return [{"id":k,"title":v["title"],"icon":v["icon"],"desc":v["desc"],
             "color":v["color"],"free_limit":v["free_limit"],
             "task_count":len(v["tasks"])} for k,v in TRACKS.items()]
